findings.suggestion:
Add a runtime guard: throw or return false when indexOf returns -1. For example:

const currentIdx = INTIMACY_ORDER.indexOf(current)
const requiredIdx = INTIMACY_ORDER.indexOf(required)
if (currentIdx === -1 || requiredIdx === -1) {
  return false // fail-closed: unknown stage does not meet requirement
}
return currentIdx >= requiredIdx

findings.code_snippet:
const hourlyCount = state.triggerTimestamps.filter(t => t > oneHourAgo).length
const dailyCount = state.triggerTimestamps.filter(t => t > oneDayAgo).length
return {
  hourlyExceeded: hourlyCount >= config.maxPerHour,
  dailyExceeded: dailyCount >= config.maxPerDay,
}

findings.suggestion:
Add an assertion or guard at the start of canTrigger or isFrequencyExceeded to validate that config values are positive integers. For example:

if (config.maxPerHour <= 0 || config.maxPerDay <= 0) {
  throw new Error(`Invalid DoNotDisturbConfig: maxPerHour=${config.maxPerHour}, maxPerDay=${config.maxPerDay} must be positive`)
}
